INSERT INTO `noticias` (`id`, `nombre`, `descripcion`, `categoria`, `imagen`, `imagen_movil`) VALUES
(1, 'Feria internacional FITUR y turismo sostenible', 'La feria internacional de turismo FITUR 2026, celebrada en Madrid, reunió a gobiernos, empresas y expertos para debatir el futuro del turismo. Uno de los temas principales fue impulsar un modelo turístico más sostenible. Durante el evento se propusieron medidas como reducir el impacto ambiental del transporte, promover alojamientos ecológicos y evitar la masificación de destinos turísticos. La feria contó con más de 255000 visitantes y generó un impacto económico de unos 505 millones de euros, lo que demuestra su importancia para el sector turístico internacional.', 'Turismo', 'energiaybiodibersidad.webp', 'energiaybiodibersidad.webp'),
(2, 'Europa impulsa políticas de viajes más ecológicos', 'Varios países europeos están promoviendo políticas para hacer el turismo más sostenible. Estas medidas incluyen fomentar el uso del tren o transporte público en lugar de vuelos cortos, apoyar hoteles con certificaciones ecológicas y proteger los ecosistemas en los destinos turísticos. Además, la Unión Europea está preparando una nueva estrategia de turismo sostenible que busca equilibrar el crecimiento económico del turismo con la protección del medio ambiente y las comunidades locales.', 'Sostenible', 'renobable.webp', 'renobable.webp'),
(3, 'Nuevos destinos de ecoturismo en África', 'En África también están surgiendo nuevos destinos que apuestan por el turismo sostenible. Las Malawi Highlands, una región montañosa del sureste de África, se están posicionando como destino internacional de aventura y ecoturismo. Los proyectos turísticos de la región buscan conservar ecosistemas naturales, apoyar a las comunidades locales y promover actividades de bajo impacto ambiental. Entre las actividades más populares destacan el senderismo en reservas naturales, el turismo comunitario, la observación de fauna y los programas de conservación ambiental.', 'Turismo', 'malawi.webp', 'malawi.webp');

